head.script:
scwin.preRowPos = 0;
scwin.statusFlag = "";
scwin.ctrtNoRowCount = 0;
scwin.tabIndex = "";

scwin.onpageload = function() {
    scwin.f_DefaultValue();
};

scwin.onUdcCompleted = function() {
};

scwin.f_initSetTab = function() {
    $c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1]);
    $c.gus.cfViewTab(0);
};

scwin.f_selectTabMenu = function(idx) {
    switch (idx) {
        case 0:
            scwin.tabIndex = "TM";
            break;
        case 1:
            scwin.tabIndex = "EX";
            break;
    }
    $c.gus.cfViewTab(idx);
};

scwin.f_DefaultValue = function() {
    scwin.f_initSetTab();
    scwin.f_selectTabMenu(0);
    scwin.f_Set("INIT");
    ed_cust.setFocus();
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_create]);
            $c.gus.cfDisableObjects([tb_DetailInfo]);
            scwin.statusFlag = "INIT";
            break;
        case "RETRIEVE":
            $c.gus.cfDisableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_create]);
            scwin.statusFlag = "RETRIEVE";
            break;
        case "RETRIEVE_D":
            $c.gus.cfEnableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfDisableBtnOnly([btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_save, btn_create]);
            $c.gus.cfDisableObjects([tb_DetailInfo]);
            scwin.statusFlag = "RETRIEVE_D";
            break;
        case "CREATE":
            $c.gus.cfDisableBtnOnly([btn_create, btn_save]);
            $c.gus.cfDisableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfEnableBtnOnly([btn_cancel, btn_save]);
            $c.gus.cfEnableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfEnableObjects([tb_DetailInfo]);
            scwin.statusFlag = "CREATE";
            break;
        case "UPDATE":
            break;
        case "SAVE":
            $c.gus.cfEnableBtnOnly([btn_save]);
            $c.gus.cfDisableObjects([tb_DetailInfo]);
            break;
        case "DELETE":
            scwin.statusFlag = "DELETE";
            break;
    }
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tb_searchCondition, null);
    switch (scwin.tabIndex) {
        case "TM":
            ds_MasterList.removeAll();
            ds_DetailInfo.removeAll();
            totalRows.setValue(ds_DetailInfo.getRowCount());
            break;
        case "EX":
            ds_TariffList.removeAll();
            totalRowsEx.setValue(ds_DetailInfo.getRowCount());
            break;
    }
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([tb_searchCondition]);
    if (!chk) {
        return;
    }
    if (!$c.gus.cfIsAfterDate(udc_cndApdt.getFromValue(), udc_cndApdt.getToValue(), false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }
    if (!(await scwin.f_ReqFieldChk("SEARCH"))) {
        return;
    }
    switch (scwin.tabIndex) {
        case "TM":
            dma_SearchParam.set("kcomcd", "DBEX");
            dma_SearchParam.set("blgb", "H");
            dma_SearchParam.set("cust", cnd_ed_cust.getValue());
            dma_SearchParam.set("liner", cnd_ed_liner.getValue());
            dma_SearchParam.set("portFrom", ed_portFrom.getValue());
            dma_SearchParam.set("portTo", ed_portTo.getValue());
            dma_SearchParam.set("apdtFrom", udc_cndApdt.getFromValue().trim());
            dma_SearchParam.set("apdtTo", udc_cndApdt.getToValue().trim());
            dma_SearchParam.set("contractno", ed_contractno.getValue());
            if (chb_triangle.getValue() != "") {
                dma_SearchParam.set("triangle", "1");
            } else {
                dma_SearchParam.set("triangle", "0");
            }
            dma_SearchParam.set("workgb", "LIST");
            ds_DetailInfo.removeAll();
            await $c.sbm.execute(sbm_retrieve);
            break;
        case "EX":
            dma_SearchParam.set("kcomcd", "DBEX");
            dma_SearchParam.set("blgb", "H");
            dma_SearchParam.set("cust", cnd_ed_cust.getValue());
            dma_SearchParam.set("liner", cnd_ed_liner.getValue());
            dma_SearchParam.set("portFrom", ed_portFrom.getValue());
            dma_SearchParam.set("portTo", ed_portTo.getValue());
            dma_SearchParam.set("apdtFrom", udc_cndApdt.getFromValue().trim());
            dma_SearchParam.set("apdtTo", udc_cndApdt.getToValue().trim());
            dma_SearchParam.set("contractno", ed_contractno.getValue());
            if (chb_triangle.getValue() != "") {
                dma_SearchParam.set("triangle", "1");
            } else {
                dma_SearchParam.set("triangle", "0");
            }
            dma_SearchParam.set("workgb", "INFOLIST");
            ds_DetailInfo.removeAll();
            await $c.sbm.execute(sbm_retrieve_list);
            break;
    }
};

scwin.f_DetailInfoRetrieve = async function(row) {
    ds_DetailInfo.removeAll();
    dma_SearchParam.set("kcomcd", ds_MasterList.getCellData(row, "kcomcd"));
    dma_SearchParam.set("blgb", "H");
    dma_SearchParam.set("cust", ds_MasterList.getCellData(row, "cust"));
    dma_SearchParam.set("liner", ds_MasterList.getCellData(row, "liner"));
    dma_SearchParam.set("portFrom", ds_MasterList.getCellData(row, "portFrom"));
    dma_SearchParam.set("portTo", ds_MasterList.getCellData(row, "portTo"));
    dma_SearchParam.set("apdtFrom", ds_MasterList.getCellData(row, "apdtFrom"));
    dma_SearchParam.set("apdtTo", ds_MasterList.getCellData(row, "apdtTo"));
    dma_SearchParam.set("contractno", ds_MasterList.getCellData(row, "contractno"));
    dma_SearchParam.set("workgb", "INFO");
    dma_SearchParam.set("dg", ds_MasterList.getCellData(row, "dg"));
    await $c.sbm.execute(sbm_retrieve_info);
};

scwin.f_AddRow = function() {
    let prevRow = ds_DetailInfo.getRowCount() - 1;
    $c.data.insertRow(ds_DetailInfo);
    let row = ds_DetailInfo.getRowPosition();
    if (prevRow >= 0) {
        ds_DetailInfo.setCellData(row, "contractno", ds_DetailInfo.getCellData(prevRow, "contractno"));
        ds_DetailInfo.setCellData(row, "contractnoTamp", ds_DetailInfo.getCellData(prevRow, "contractnoTamp"));
        ds_DetailInfo.setCellData(row, "cust", ds_DetailInfo.getCellData(prevRow, "cust"));
        ds_DetailInfo.setCellData(row, "custnm", ds_DetailInfo.getCellData(prevRow, "custnm"));
        ds_DetailInfo.setCellData(row, "liner", ds_DetailInfo.getCellData(prevRow, "liner"));
        ds_DetailInfo.setCellData(row, "linernm", ds_DetailInfo.getCellData(prevRow, "linernm"));
        ds_DetailInfo.setCellData(row, "portFrom", ds_DetailInfo.getCellData(prevRow, "portFrom"));
        ds_DetailInfo.setCellData(row, "portFromNm", ds_DetailInfo.getCellData(prevRow, "portFromNm"));
        ds_DetailInfo.setCellData(row, "portTo", ds_DetailInfo.getCellData(prevRow, "portTo"));
        ds_DetailInfo.setCellData(row, "portToNm", ds_DetailInfo.getCellData(prevRow, "portToNm"));
        ds_DetailInfo.setCellData(row, "apdtFrom", ds_DetailInfo.getCellData(prevRow, "apdtFrom"));
        ds_DetailInfo.setCellData(row, "apdtTo", ds_DetailInfo.getCellData(prevRow, "apdtTo"));
    }
    ds_DetailInfo.setCellData(row, "dg", "N");
    ds_DetailInfo.setCellData(row, "kcomcd", "DBEX");
    ds_DetailInfo.setCellData(row, "blgb", "H");
    ds_DetailInfo.setCellData(row, "curr", "USD");
    gr_DetailInfo.setFocusedCell(row, "item");
    if (ds_DetailInfo.getUpdatedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
    scwin.f_ContractInfo();
};

scwin.btn_addRow_onclick = function(e) {
    scwin.f_AddRow();
};

scwin.f_DelRow = function() {
    ds_DetailInfo.removeRow(ds_DetailInfo.getRowPosition());
    if (ds_DetailInfo.getUpdatedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

scwin.btn_deleteRow_onclick = function(e) {
    scwin.f_DelRow();
};

scwin.f_DelRowAll = async function() {
    let chk = await $c.win.confirm("전체 삭제을 적용하시겠습니까?");
    if (chk) {
        for (let i = ds_DetailInfo.getRowCount() - 1; i >= 0; i--) {
            ds_DetailInfo.removeRow(i);
        }
    }
    if (ds_DetailInfo.getUpdatedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

scwin.btn_deleteRowAll_onclick = function(e) {
    scwin.f_DelRowAll();
};

scwin.f_UndoRow = function() {
    ds_DetailInfo.undoRow(ds_DetailInfo.getRowPosition());
    if (ds_DetailInfo.getUpdatedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

scwin.btn_undoRow_onclick = function(e) {
    scwin.f_UndoRow();
};

scwin.f_Save = async function() {
    if (ds_DetailInfo.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Container Selling Tariff"]);
        return false;
    }
    let rowCnt = ds_DetailInfo.getRowCount();
    for (let row = 0; row < rowCnt; row++) {
        if (!$c.gus.cfIsAfterDate(ds_DetailInfo.getCellData(row, "apdtFrom"), ds_DetailInfo.getCellData(row, "apdtTo"), false)) {
            await $c.gus.cfAlertMsg("[" + (row + 1) + "] Line Is" + MSG_CM_ERR_039);
            return;
        }
    }
    if (await scwin.f_ReqFieldChk("DEATAIL_SEARCH")) {
        let chk = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk) {
            await $c.sbm.execute(sbm_save);
        }
    }
};

scwin.btn_save_onclick = function(e) {
    scwin.f_Save();
};

scwin.f_Save_Ex = async function() {
    if (ds_TariffList.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Container Selling Tariff"]);
        return false;
    }
    if (await scwin.f_ReqFieldChk("TARIFFLIST")) {
        let chk = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk) {
            await $c.sbm.execute(sbm_save_list);
        }
    }
};

scwin.btn_save_ex_onclick = function(e) {
    scwin.f_Save_Ex();
};

scwin.f_Cancel = function() {
    ds_MasterList.undoAll();
    ds_DetailInfo.undoAll();
    scwin.f_Set("RETRIEVE");
};

scwin.btn_cancel_onclick = function(e) {
    scwin.f_Cancel();
};

scwin.f_Create = function() {
    ds_DetailInfo.removeAll();
    ds_ctrtNo.removeAll();
    scwin.f_AddRow();
    let row = ds_DetailInfo.getRowPosition();
    let mRow = ds_MasterList.getRowPosition();
    if (mRow >= 0) {
        ds_DetailInfo.setCellData(row, "cust", ds_MasterList.getCellData(mRow, "cust"));
        ds_DetailInfo.setCellData(row, "custnm", ds_MasterList.getCellData(mRow, "custnm"));
        ds_DetailInfo.setCellData(row, "contractno", ds_MasterList.getCellData(mRow, "contractno"));
        ds_DetailInfo.setCellData(row, "contractnoTamp", ds_MasterList.getCellData(mRow, "contractno"));
        ds_DetailInfo.setCellData(row, "liner", ds_MasterList.getCellData(mRow, "liner"));
        ds_DetailInfo.setCellData(row, "linernm", ds_MasterList.getCellData(mRow, "linernm"));
        ds_DetailInfo.setCellData(row, "portFrom", ds_MasterList.getCellData(mRow, "portFrom"));
        ds_DetailInfo.setCellData(row, "portFromNm", ds_MasterList.getCellData(mRow, "portFromNm"));
        ds_DetailInfo.setCellData(row, "portTo", ds_MasterList.getCellData(mRow, "portTo"));
        ds_DetailInfo.setCellData(row, "portToNm", ds_MasterList.getCellData(mRow, "portToNm"));
        ds_DetailInfo.setCellData(row, "apdtFrom", ds_MasterList.getCellData(mRow, "apdtFrom"));
        ds_DetailInfo.setCellData(row, "apdtTo", ds_MasterList.getCellData(mRow, "apdtTo"));
    }
    ds_DetailInfo.setCellData(row, "kcomcd", "DBEX");
    ds_DetailInfo.setCellData(row, "blgb", "H");
    scwin.f_ContractInfo();
    scwin.f_Set("CREATE");
    ed_cust.setFocus();
};

scwin.btn_create_onclick = function(e) {
    scwin.f_Create();
};

scwin.f_Delete = function() {
};

scwin.f_Print = function() {
    let strOrderDetailUrl = "";
    strOrderDetailUrl = "";
    $c.gus.cfTabMenuAdd(strOrderDetailUrl, "");
};

scwin.f_ReqFieldChk = async function(workGb) {
    switch (workGb) {
        case "SEARCH":
            let chk1 = await $c.gus.cfValidate([tb_searchCondition]);
            if (chk1 == false) {
                return false;
            } else {
                return true;
            }
            break;
        case "DEATAIL_SEARCH":
            let chk2 = await $c.gus.cfValidate([tb_DetailInfo, gr_DetailInfo]);
            if (chk2 == false) {
                return false;
            } else {
                return true;
            }
            break;
        case "TARIFFLIST":
            let chk3 = await $c.gus.cfValidate([gr_TariffList]);
            if (chk3 == false) {
                return false;
            } else {
                return true;
            }
            break;
    }
};

scwin.f_PopUp = function(pPopGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let pCode = "";
    let pName = "";
    let rtnList = null;

    switch (pPopGubun) {
        case "Customer_C":
            pCode = cnd_ed_cust.getValue().trim();
            pName = cnd_txt_custnm.getValue();
            udc_ilcomCode_cnd_cust.ilCommonPopUp(scwin.callbackCustomerC,
                pCode, pName, pWinCloseTF, '2', 'Customer Code,Customer Name,',
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Customer Search,Customer Code,Customer Name", 'F');
            break;
        case "Loading_C":
            pCode = ed_portFrom.getValue().trim();
            pName = "";
            udc_ilcomCode_cnd_portFrom.ilCommonPopUp(scwin.callbackLoadingC,
                pCode, pName, pWinCloseTF, '2', "Loading Code, Loading Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Loading Search,Loading Code,Loading Name", pNoDataCloseTF);
            break;
        case "Discharge_C":
            pCode = ed_portTo.getValue().trim();
            pName = "";
            udc_ilcomCode_cnd_portTo.ilCommonPopUp(scwin.callbackDischargeC,
                pCode, pName, pWinCloseTF, '2', "Discharge Code,Discharge Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Discharge Search,Discharge Code,Discharge Name", pNoDataCloseTF);
            break;
        case "Liner_C":
            pCode = cnd_ed_liner.getValue().trim();
            pName = cnd_txt_linernm.getValue();
            udc_ilcomCode_cnd_liner.ilCommonPopUp(scwin.callbackLinerC,
                pCode, pName, pWinCloseTF, '2', "Liner Code,Liner Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Liner Search,Liner Code,Liner Name", pNoDataCloseTF);
            break;
        case "Customer":
            pCode = ed_cust.getValue().trim();
            pName = txt_custnm.getValue();
            udc_ilcomCode_cust.ilCommonPopUp(scwin.callbackCustomer,
                pCode, pName, pWinCloseTF, '2', 'Customer Code,Customer Name,',
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Customer Search,Customer Code,Customer Name", pNoDataCloseTF);
            break;
        case "Loading":
            pCode = ed_portFrom.getValue().trim();
            pName = txt_portFromnm.getValue();
            udc_ilcomCode_portFrom.ilCommonPopUp(scwin.callbackLoading,
                pCode, pName, pWinCloseTF, '2', "Loading Code, Loading Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Loading Search,Loading Code,Loading Name", pNoDataCloseTF);
            break;
        case "Discharge":
            pCode = ed_portTo.getValue().trim();
            pName = txt_portTonm.getValue();
            udc_ilcomCode_portTo.ilCommonPopUp(scwin.callbackDischarge,
                pCode, pName, pWinCloseTF, '2', "Discharge Code,Discharge Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Discharge Search,Discharge Code,Discharge Name", pNoDataCloseTF);
            break;
        case "Liner":
            pCode = ed_liner.getValue().trim();
            pName = txt_linernm.getValue();
            udc_ilcomCode_liner.ilCommonPopUp(scwin.callbackLiner,
                pCode, pName, pWinCloseTF, '2', "Liner Code,Liner Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Liner Search,Liner Code,Liner Name", pNoDataCloseTF);
            break;
    }
};

scwin.callbackCustomerC = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_cust, cnd_txt_custnm);
};

scwin.callbackLoadingC = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_portFrom, "");
};

scwin.callbackDischargeC = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_portTo, "");
};

scwin.callbackLinerC = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_liner, cnd_txt_linernm);
};

scwin.callbackCustomer = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_cust, txt_custnm);
    if (typeof(rtnList) != "undefined") {
        if (rtnList[0].trim() != "N/A") {
            scwin.f_ContractInfo();
        }
    }
};

scwin.callbackLoading = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_portFrom, txt_portFromnm);
};

scwin.callbackDischarge = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_portTo, txt_portTonm);
};

scwin.callbackLiner = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_liner, txt_linernm);
};

scwin.f_PopUpGrid = function(disGubun, row, pWinCloseTF, pAllSearchTF) {
    let rtnList;
    switch (disGubun) {
        case "Customer":
            let pCodeCust = ds_DetailInfo.getCellData(row, "cust");
            let pNameCust = "";
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "cust", "", [""]);
            }, pCodeCust, pNameCust, pWinCloseTF, '2', "Customer Code,Customer Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Customer Search,Customer Code,Customer Name", 'F');
            break;
        case "Liner":
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "liner", "", [""]);
            }, ds_DetailInfo.getCellData(row, "liner"), '', pWinCloseTF, '2', "Liner Code,Liner Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Liner Search,Liner Code,Liner Name", 'F');
            break;
        case "Loading":
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "portFrom", "", [""]);
            }, ds_DetailInfo.getCellData(row, "portFrom"), '', pWinCloseTF, '2', "Loading Code,Loading Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Loading Search,Loading Code,Loading Name", 'F');
            break;
        case "Discharge":
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "portTo", "", [""]);
            }, ds_DetailInfo.getCellData(row, "portTo"), '', pWinCloseTF, '2', "Discharge Code,Discharge Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Discharge Search,Discharge Code,Discharge Name", 'F');
            break;
        case "Item":
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "item", "itemnm", [""]);
            }, ds_DetailInfo.getCellData(row, "item"), '', pWinCloseTF, '2', "Item Code,Item Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Item Search,Item Code,Item Name", 'F');
            break;
        case "Freight":
            let arry = ["", "selpchItemCd", "", "", "", "", "", ""];
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "fcode", "fcodenm", arry);
            }, ds_DetailInfo.getCellData(row, "fcode"), '', pWinCloseTF, '2', "Freight Code, Freight Name,",
                '130,300', "3,4,5,6,7,8,9,10", 'S', '500', '500', null, null, null,
                pAllSearchTF, "Freight Search,Freight Code,Freight Name", 'F');
            break;
        case "CNTR_TYPE":
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "type", "typenm", [""]);
            }, ds_DetailInfo.getCellData(row, "type"), '', pWinCloseTF, '10', "Container Code, Container Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Container Type Search,Container Code,Container Name", 'F');
            break;
        case "Currency":
            let pCodeCurr = ds_DetailInfo.getCellData(row, "curr");
            let pNameCurr = "";
            udc_ilcomCode_Grid.ilCommonPopUp(function(rtn) {
                $c.gus.cfSetGridReturnValue(rtn, ds_DetailInfo, row, "curr", "", [""]);
            }, pCodeCurr, pNameCurr, pWinCloseTF, '10', "Currency Code, Currency Name,",
                '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null,
                pAllSearchTF, "Currency Search,Currency Code,Currency Name", 'F');
            break;
        default:
            break;
    }
};

scwin.f_BeforePopUpEd = function(nmObj, cdObj, gubun1, pWinCloseTF, pAllSearchTF) {
    let cdObjVal = cdObj.getValue().trim();
    if (cdObj.modified) {
        if (cdObjVal == "") {
            nmObj.setValue("");
        } else {
            nmObj.setValue("");
            scwin.f_PopUp(gubun1, pWinCloseTF, pAllSearchTF);
        }
    }
};

scwin.f_ChkPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_PopUp(disGubun, 'T', 'T', 'F');
    } else {
        scwin.f_PopUp(disGubun, 'T', 'T', 'F');
    }
};

scwin.f_DownExcelSheet = async function() {
    if (ds_DetailInfo.getRowCount() != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
