scwin.f_ExcelUp = async function() {
    if (scwin.statusFlag != "CREATE") {
        await $c.win.alert("신규모드에서 실행 가능합니다.");
        return;
    }
    let upRow = 0;
    ds_DetailInfo.removeAll();

    // TODO: CSV 파일 업로드 및 파싱은 WebSquare 엑셀 업로드 UDC로 대체 필요
    // 원본 GAUCE의 inputF(INPUTFILE ActiveX) + CSV 파싱 로직은 1:1 변환 불가
    // WebSquare에서는 $c.data.uploadGridViewExcel 또는 별도 CSV 업로드 기능 사용

    let cntrRow = ds_DetailInfo.getRowCount();

    for (let i = 1; i < ds_tmp_tariff.getRowCount(); i++) {
        $c.data.insertRow(ds_DetailInfo);
        let row = ds_DetailInfo.getRowPosition();

        ds_DetailInfo.setCellData(row, "cust", $c.str.lpad(ds_tmp_tariff.getCellData(i, "cust"), 6, '0'));
        ds_DetailInfo.setCellData(row, "contractno", ds_tmp_tariff.getCellData(i, "contractno"));
        ds_DetailInfo.setCellData(row, "contractnoTamp", ds_tmp_tariff.getCellData(i, "contractno"));
        ds_DetailInfo.setCellData(row, "liner", ds_tmp_tariff.getCellData(i, "liner"));
        ds_DetailInfo.setCellData(row, "portFrom", ds_tmp_tariff.getCellData(i, "portFrom"));
        ds_DetailInfo.setCellData(row, "portTo", ds_tmp_tariff.getCellData(i, "portTo"));
        ds_DetailInfo.setCellData(row, "item", ds_tmp_tariff.getCellData(i, "item"));
        ds_DetailInfo.setCellData(row, "fcode", ds_tmp_tariff.getCellData(i, "fcode"));
        ds_DetailInfo.setCellData(row, "selpchItemCd", ds_tmp_tariff.getCellData(i, "selpchItemCd"));
        ds_DetailInfo.setCellData(row, "type", ds_tmp_tariff.getCellData(i, "type"));
        ds_DetailInfo.setCellData(row, "curr", ds_tmp_tariff.getCellData(i, "curr"));
        ds_DetailInfo.setCellData(row, "amount", ds_tmp_tariff.getCellData(i, "amount"));

        let dgVal = ds_tmp_tariff.getCellData(i, "dg").toUpperCase();
        if (dgVal == "YES" || dgVal == "Y") {
            ds_DetailInfo.setCellData(row, "dg", "Y");
        } else {
            ds_DetailInfo.setCellData(row, "dg", "N");
        }

        let apdtFromVal = ds_tmp_tariff.getCellData(i, "apdtFrom").replace(/\//g, "").replace(/-/g, "");
        ds_DetailInfo.setCellData(row, "apdtFrom", apdtFromVal);
        let apdtToVal = ds_tmp_tariff.getCellData(i, "apdtTo").replace(/\//g, "").replace(/-/g, "");
        ds_DetailInfo.setCellData(row, "apdtTo", apdtToVal);

        if (ds_tmp_tariff.getCellData(i, "blgb").toUpperCase() == "M") {
            ds_DetailInfo.setCellData(row, "blgb", "M");
        } else {
            ds_DetailInfo.setCellData(row, "blgb", "H");
        }

        ds_DetailInfo.setCellData(row, "kcomcd", "DBEX");

        if (scwin.f_PopUpExcel("Customer", row, "T", "T", "K") != true) {
            await $c.win.alert((row + 1) + " 행의 Customer 코드 오류입니다. 확인 하십시요.");
            ds_DetailInfo.removeAll();
            break;
        }
        scwin.f_ContractInfo();
        scwin.f_ContractInfoVaildation(ds_DetailInfo.getCellData(row, "cust"), ds_DetailInfo.getCellData(row, "contractno"));

        if (ds_ctrtNoIsNull.getRowCount() == 0) {
            await $c.win.alert((row + 1) + " 행의 해당 거래처에 계약번호가 존재하지 않습니다.");
            ds_DetailInfo.removeAll();
            break;
        }
        if (!$c.gus.cfIsAfterDate(ds_DetailInfo.getCellData(row, "apdtFrom"), ds_DetailInfo.getCellData(row, "apdtTo"), false)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ds_DetailInfo.removeAll();
            break;
        }

        if (ds_DetailInfo.getCellData(row, "liner").trim() != "") {
            if (scwin.f_PopUpExcel("Liner", row, "T", "T", "K") != true) {
                await $c.win.alert((row + 1) + " 행의 Liner 코드 오류입니다. 확인 하십시요.");
                ds_DetailInfo.removeAll();
                break;
            }
        }

        if (scwin.f_PopUpExcel("Loading", row, "T", "T", "K") != true || ds_DetailInfo.getCellData(row, "portFrom").length < 5) {
            await $c.win.alert((row + 1) + " 행의 Loading 코드 오류입니다. 확인 하십시요.");
            ds_DetailInfo.removeAll();
            break;
        }

        if (scwin.f_PopUpExcel("Discharge", row, "T", "T", "K") != true || ds_DetailInfo.getCellData(row, "portTo").length < 5) {
            await $c.win.alert((row + 1) + " 행의 Discharge 코드 오류입니다. 확인 하십시요.");
            ds_DetailInfo.removeAll();
            break;
        }

        if (ds_DetailInfo.getCellData(row, "item").trim() != "") {
            if (scwin.f_PopUpExcel("Item", row, "T", "T", "K") != true) {
                await $c.win.alert((row + 1) + " 행의 Item 코드 오류입니다. 확인 하십시요.");
                ds_DetailInfo.removeAll();
                break;
            }
        }

        if (scwin.f_PopUpExcel("Freight", row, "T", "T", "K") != true || ds_DetailInfo.getCellData(row, "fcode").length < 3) {
            await $c.win.alert((row + 1) + " 행의 Freight 코드 오류입니다. 확인 하십시요.");
            ds_DetailInfo.removeAll();
            break;
        }

        if (scwin.f_PopUpExcel("CNTR_TYPE", row, "T", "T", "K") != true || ds_DetailInfo.getCellData(row, "type").length < 3) {
            await $c.win.alert((row + 1) + " 행의 CNTR_TYPE 코드 오류입니다. 확인 하십시요.");
            ds_DetailInfo.removeAll();
            break;
        }

        if (scwin.f_PopUpExcel("Currency", row, "T", "T", "K") != true || ds_DetailInfo.getCellData(row, "curr").length < 3) {
            await $c.win.alert((row + 1) + " 행의 Currency 코드 오류입니다. 확인 하십시요.");
            ds_DetailInfo.removeAll();
            break;
        }
    }

    upRow = ds_DetailInfo.getRowCount();
    totalRows.setValue(upRow);
    if (ds_DetailInfo.getRowCount() > 0) {
        ds_DetailInfo.setRowPosition(0);
    }
};

