                } else {
                    return false;
                }
            }
            break;
        case "Freight":
            rtnList = udc_ilcomCode_Grid.ilCommonPopUpSync('retriveFreightCodeInfo',
                ds_DetailInfo.getCellData(row, "fcode").trim(), '', pWinCloseTF, '10',
