                return true;
            } else {
                return false;
            }
            break;
        case "CNTR_TYPE":
            rtnList = udc_ilcomCode_Grid.ilCommonPopUpSync('retriveContainerTypeCodeInfo',
                ds_DetailInfo.getCellData(row, "type").trim(), '', pWinCloseTF, '10',
                "Container Code, Container Name,", '130,300', "3,4,5,6,7,8,9,10", null,
                '500', '500', null, null, null, pAllSearchTF,
                "Container Type Search,Container Code,Container Name", pNoDataCloseTF);
            if (rtnList != "") {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "type", "typenm", [""]);
                return true;
            } else {
                return false;
            }
            break;
        case "Currency":
            rtnList = udc_ilcomCode_Grid.ilCommonPopUpSync('retriveCurrencyCodeInfo',
                ds_DetailInfo.getCellData(row, "curr").trim(), '', pWinCloseTF, '10',
                "Currency Code, Currency Name,", '130,300', "3,4,5,6,7,8,9,10", null,
                '500', '500', null, null, null, pAllSearchTF,
                "Currency Search,Currency Code,Currency Name", pNoDataCloseTF);
            if (rtnList != "") {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "curr", "", [""]);
                return true;
            } else {
                return false;
            }
            break;
        default:
            break;
    }
};

