            rtnList = udc_ilcomCode_Grid.ilCommonPopUpSync('retrieveCommGoodsInfo',
                ds_TariffList.getCellData(row, "item").trim(), '', pWinCloseTF, '2',
                "Item Code,Item Name,", '130,300', "3,4,5,6,7,8,9,10", null,
                '500', '500', null, null, null, pAllSearchTF,
                "Item Search,Item Code,Item Name", pNoDataCloseTF);
            if (typeof(rtnList) != "undefined") {
                if (rtnList != "") {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_TariffList, row, "item", "itemnm", [""]);
                    return true;
                } else {
                    return false;
                }
            }
            break;
        case "Freight":
            rtnList = udc_ilcomCode_Grid.ilCommonPopUpSync('retriveFreightCodeInfo',
                ds_TariffList.getCellData(row, "fcode").trim(), '', pWinCloseTF, '10',
                "Freight Code, Freight Name,", '130,300', "3,4,5,6,7,8,9,10", 'S',
                '500', '500', null, null, null, pAllSearchTF,
                "Freight Search,Freight Code,Freight Name", pNoDataCloseTF);
            let arry = ["", "selpchItemCd", "", "", "", "", "", ""];
            if (rtnList != "") {
                $c.gus.cfSetGridReturnValue(rtnList, ds_TariffList, row, "fcode", "fcodenm", arry);
                return true;
            } else {
                return false;
            }
            break;
        case "CNTR_TYPE":
            rtnList = udc_ilcomCode_Grid.ilCommonPopUpSync('retriveContainerTypeCodeInfo',
                ds_TariffList.getCellData(row, "type").trim(), '', pWinCloseTF, '10',
                "Container Code, Container Name,", '130,300', "3,4,5,6,7,8,9,10", null,
                '500', '500', null, null, null, pAllSearchTF,
                "Container Type Search,Container Code,Container Name", pNoDataCloseTF);
            if (rtnList != "") {
                $c.gus.cfSetGridReturnValue(rtnList, ds_TariffList, row, "type", "typenm", [""]);
                return true;
            } else {
                return false;
            }
            break;
        case "Currency":
            rtnList = udc_ilcomCode_Grid.ilCommonPopUpSync('retriveCurrencyCodeInfo',
                ds_TariffList.getCellData(row, "curr").trim(), '', pWinCloseTF, '10',
                "Currency Code, Currency Name,", '130,300', "3,4,5,6,7,8,9,10", null,
                '500', '500', null, null, null, pAllSearchTF,
                "Currency Search,Currency Code,Currency Name", pNoDataCloseTF);
            if (rtnList != "") {
                $c.gus.cfSetGridReturnValue(rtnList, ds_TariffList, row, "curr", "", [""]);
                return true;
            } else {
                return false;
            }
            break;
        default:
            break;
    }
};

