scwin.ds_MasterList_onloadcompleted = async function(e) {
    let rowcnt = ds_MasterList.getRowCount();
    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        scwin.f_Set("INIT");
    }
};

scwin.ds_ctrtNoIsNull_onloadcompleted = function(e) {
    let rowcnt = ds_ctrtNoIsNull.getRowCount();
    if (rowcnt == 0) {
        scwin.ctrtNoRowCount = rowcnt;
    }
};

scwin.ds_DetailInfo_onloadcompleted = async function(e) {
    let rowcnt = ds_DetailInfo.getRowCount();
    totalRows.setValue(rowcnt);
    $c.gus.cfGoPrevPosition(ds_DetailInfo, scwin.preRowPos);

    scwin.f_Set("SAVE");
    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        scwin.f_Set("INIT");
    } else {
        scwin.f_ContractInfo();
    }

    gr_DetailInfo.setColumnProperty("item", "readOnly", true);
    gr_DetailInfo.setColumnProperty("fcode", "readOnly", true);
    gr_DetailInfo.setColumnProperty("curr", "readOnly", true);
    gr_DetailInfo.setColumnProperty("type", "readOnly", true);
};

scwin.ds_TariffList_onloadcompleted = async function(e) {
    let rowcnt = ds_TariffList.getRowCount();
    totalRowsEx.setValue(rowcnt);

    scwin.f_Set("SAVE");
    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        scwin.f_Set("INIT");
    }
};

scwin.ds_MasterList_onrowpositionchange = function(e) {
    let row = ds_MasterList.getRowPosition();
    if (row >= 0) {
        scwin.preRowPos = row;
        scwin.f_DetailInfoRetrieve(row);
        scwin.f_Set("RETRIEVE_D");
    }
};

scwin.ds_MasterList_canrowpositionchange = async function(e) {
    if (ds_DetailInfo.getUpdatedIndex().length > 0) {
        let chk = await $c.win.confirm(MSG_CM_ERR_042);
        if (chk) {
            return false;
        } else {
            return true;
        }
    }
};

scwin.ds_DetailInfo_onrowpositionchange = function(e) {
    let row = ds_DetailInfo.getRowPosition();
    scwin.f_ContractInfo();

    if (row >= 0 && ds_DetailInfo.getRowStatus(row) == "C") {
        gr_DetailInfo.setColumnProperty("item", "readOnly", false);
        gr_DetailInfo.setColumnProperty("fcode", "readOnly", false);
        gr_DetailInfo.setColumnProperty("curr", "readOnly", false);
        gr_DetailInfo.setColumnProperty("type", "readOnly", false);
    } else {
        gr_DetailInfo.setColumnProperty("item", "readOnly", true);
        gr_DetailInfo.setColumnProperty("fcode", "readOnly", true);
        gr_DetailInfo.setColumnProperty("curr", "readOnly", true);
        gr_DetailInfo.setColumnProperty("type", "readOnly", true);
    }
};

